import type { Extent, Point } from "../../portal/jsonTypes.js";

/**
 * A color represented as an array of RGBA values, where each value is a number between 0 and 255.
 *
 * @since 5.0
 */
export type CIMColor = [
    number,
    number,
    number,
    number
];

/**
 * Represents a primitive override. A primitive override allows you to use an Arcade expression to dynamically change
 * a property on a symbol layer based on data values. This is used with the [Arcade visualization profile](https://developers.arcgis.com/javascript/latest/arcade/#visualization),
 * which gives access to `$feature` and `$view.scale` profile variables. This allows you to override symbol layer properties
 * based on a feature attribute at the current scale of the view.
 *
 * **Using `$view.scale`:**
 * The following JSON snippet shows a primitive override on the `size` property for a symbol layer with the primitiveName
 * `"symbol-layer-1"`. Based on the Arcade expression, the size of the symbol layer will update as the view scale changes.
 * ```json
 * {
 *    type: "CIMPrimitiveOverride",
 *    primitiveName: "symbol-layer-1", // the name of the symbol layer we want to override
 *    propertyName: "Size", // the name of the property on the symbol layer we want to override
 *    valueExpressionInfo: {
 *      type: "CIMExpressionInfo",
 *      title: "Size override",
 *      // the pixel size at the largest scale
 *      // 42 represents the pixel size of the
 *      // circles at the view's largest scale (1:2,311,161)
 *      expression: "42 * 2311161 / $view.scale",
 *      returnType: "Default"
 *    }
 * }
 * ```
 *
 * **Using `$feature`:**
 * The following JSON snippet shows a primitive override on the `textString` property of a [markerGraphic](https://developers.arcgis.com/javascript/latest/references/core/symbols/cim/types/#CIMMarkerGraphic) with the primitive name `"textGraphic"`. The value of `textGraphic` will be based on the value of `NAME` for each feature.
 *
 * ```json
 * {
 *  type: "CIMPrimitiveOverride",
 *  primitiveName: "textGraphic",
 *  propertyName: "TextString",
 *  valueExpressionInfo: {
 *    type: "CIMExpressionInfo",
 *    title: "Custom",
 *    expression: "$feature.NAME", // value of textString will be based on the NAME of the feature
 *    returnType: "Default"
 *  }
 * }
 * ```
 *
 * @since 5.0
 * @see [CIMSymbolReference.primitiveOverrides](https://developers.arcgis.com/javascript/latest/references/core/symbols/cim/types/#CIMSymbolReference)
 * @see [Sample - CIMSymbol (PrimitiveOverride on TextString)](https://developers.arcgis.com/javascript/latest/sample-code/cim-symbols/)
 * @see [Sample - Symbol animations](https://developers.arcgis.com/javascript/latest/sample-code/cim-animations/)
 */
export interface CIMPrimitiveOverride {
  /** @since 5.0 */
  type: "CIMPrimitiveOverride";
  /**
   * The primitive name this override applies to.
   *
   * @since 5.0
   */
  primitiveName: string;
  /**
   * The name of the property in the primitive this override applies to (e.g. "Size"). This value must be in Proper case (e.g. "Size" not "size").
   *
   * @since 5.0
   */
  propertyName: string;
  /**
   * Contains the Arcade expression that returns a value to be applied to the property on the primitive.
   *
   * @since 5.0
   */
  valueExpressionInfo?: CIMExpressionInfo;
}

/** @since 5.0 */
export interface CIMColorRamp {}

/**
 * Represents a color scheme composed of discrete colors.
 *
 * ```json
 * colorRamp: {
 *   type: "CIMFixedColorRamp",
 *   colors: [
 *     [166, 38, 57, 255],
 *     [71, 121, 152, 255],
 *     [255, 196, 130, 255],
 *     [196, 144, 209, 255],
 *     [182, 238, 166, 255]
 *   ]
 * }
 * ```
 *
 * @since 4.32
 */
export interface CIMFixedColorRamp extends CIMColorRamp {
  /** @since 5.0 */
  type: "CIMFixedColorRamp";
  /**
   * The ordered list of colors in the color scheme. The colors are applied in the order they are defined.
   *
   * @since 5.0
   */
  colors: CIMColor[];
}

/**
 * Represents a continuous color ramp scheme - a color ramp that has a continuous transition between two colors.
 *
 * @since 5.0
 */
export interface CIMContinuousColorRamp extends CIMColorRamp {
  /**
   * The color at the start of the ramp.
   *
   * @since 5.0
   */
  fromColor: CIMColor;
  /**
   * The color at the end of the ramp.
   *
   * @since 5.0
   */
  toColor: CIMColor;
}

/**
 * Represents a linear continuous color ramp scheme - a color ramp that has a linear transition between two colors. This ramp is created using the CIELAB algorithm which blends two colors without traversing the intervening hue space.
 *
 * ```json
 * colorRamp: {
 *   type: "CIMMultipartColorRamp",
 *   colorRamps: [
 *     {
 *       type: "CIMLinearContinuousColorRamp",
 *       fromColor: [255, 255, 255, 255], // white
 *       toColor: [190, 232, 255, 255] // light blue
 *     }
 *   ],
 *   weights: [1]
 * }
 * ```
 *
 * @since 4.32
 */
export interface CIMLinearContinuousColorRamp extends CIMContinuousColorRamp {
  /** @since 5.0 */
  type: "CIMLinearContinuousColorRamp";
}

/**
 * Represents a multipart color ramp scheme - a color ramp defined by combining two or more continuous or fixed ramps.
 *
 * ```json
 * colorRamp: {
 *   type: "CIMMultipartColorRamp",
 *   colorRamps: [
 *     {
 *       type: "CIMLinearContinuousColorRamp",
 *       fromColor: [0, 76, 115, 255],
 *       toColor: [0, 132, 168, 255]
 *     },
 *     {
 *       type: "CIMLinearContinuousColorRamp",
 *       fromColor: [0, 132, 168, 255],
 *       toColor: [255, 255, 255, 255]
 *     }
 *   ],
 *   weights: [0.3, 0.7]
 * }
 * ```
 *
 * @since 4.32
 */
export interface CIMMultipartColorRamp extends CIMColorRamp {
  /** @since 5.0 */
  type: "CIMMultipartColorRamp";
  /**
   * An ordered list of color ramps that are combined to build the multipart color ramp. Typically these are continuous color ramps.
   *
   * @since 5.0
   */
  colorRamps: CIMColorRampUnion[];
  /**
   * The proportional weight for each color ramp that make up the multipart ramp. This allows for ramp to ramp transition at specific weight points. The number of weights must match the number of color ramps.
   *
   * @since 5.0
   */
  weights: number[];
}

/**
 * Represents a color ramp.
 *
 * @since 4.32
 * @see [CIMGradientFill.colorRamp](https://developers.arcgis.com/javascript/latest/references/core/symbols/cim/types/#CIMGradientFill)
 * @see [CIMGradientStroke.colorRamp](https://developers.arcgis.com/javascript/latest/references/core/symbols/cim/types/#CIMGradientStroke)
 */
export type CIMColorRampUnion = CIMLinearContinuousColorRamp | CIMFixedColorRamp | CIMMultipartColorRamp;

/**
 * Represents a callout for a point symbol.
 *
 * @since 5.0
 */
export interface CIMCallout {}

/** @since 5.0 */
export interface CIMLineCallout extends CIMCallout {}

/**
 * Represents a background callout for a [CIMTextSymbol](https://developers.arcgis.com/javascript/latest/references/core/symbols/cim/types/#CIMTextSymbol).
 *
 * @since 4.26
 * @see [CIMTextSymbol.callout](https://developers.arcgis.com/javascript/latest/references/core/symbols/cim/types/#CIMTextSymbol)
 */
export interface CIMBackgroundCallout extends CIMLineCallout {
  /**
   * The callout type.
   *
   * @since 5.0
   */
  type: "CIMBackgroundCallout";
  /**
   * The symbol used to draw the background.
   * > Currently, only CIMSolidStroke and CIMSolidFill symbol layers without geometric effects are supported within this symbol.
   *
   * @since 5.0
   */
  backgroundSymbol: CIMPolygonSymbol;
}

/** @since 5.0 */
export type CIMGeometricEffects = CIMGeometricEffect[];

/**
 * Represents a geometric effect.
 *
 * @since 5.0
 * @see [CIMPointSymbol.effects](https://developers.arcgis.com/javascript/latest/references/core/symbols/cim/types/#CIMPointSymbol)
 * @see [CIMLineSymbol.effects](https://developers.arcgis.com/javascript/latest/references/core/symbols/cim/types/#CIMLineSymbol)
 * @see [CIMPolygonSymbol.effects](https://developers.arcgis.com/javascript/latest/references/core/symbols/cim/types/#CIMPolygonSymbol)
 * @see [CIMHatchFill.effects](https://developers.arcgis.com/javascript/latest/references/core/symbols/cim/types/#CIMHatchFill)
 * @see [CIMPictureFill.effects](https://developers.arcgis.com/javascript/latest/references/core/symbols/cim/types/#CIMPictureFill)
 * @see [CIMPictureMarker.effects](https://developers.arcgis.com/javascript/latest/references/core/symbols/cim/types/#CIMPictureMarker)
 * @see [CIMPictureStroke.effects](https://developers.arcgis.com/javascript/latest/references/core/symbols/cim/types/#CIMPictureStroke)
 * @see [CIMSolidFill.effects](https://developers.arcgis.com/javascript/latest/references/core/symbols/cim/types/#CIMSolidFill)
 * @see [CIMSolidStroke.effects](https://developers.arcgis.com/javascript/latest/references/core/symbols/cim/types/#CIMSolidStroke)
 * @see [CIMVectorMarker.effects](https://developers.arcgis.com/javascript/latest/references/core/symbols/cim/types/#CIMVectorMarker)
 * @see [CIMGradientStroke.effects](https://developers.arcgis.com/javascript/latest/references/core/symbols/cim/types/#CIMGradientStroke)
 * @see [CIMGradientFill.effects](https://developers.arcgis.com/javascript/latest/references/core/symbols/cim/types/#CIMGradientFill)
 */
export type CIMGeometricEffect = CIMGeometricEffectAddControlPoints | CIMGeometricEffectAddControlPoints | CIMGeometricEffectArrow | CIMGeometricEffectBuffer | CIMGeometricEffectControlMeasureLine | CIMGeometricEffectCut | CIMGeometricEffectDashes | CIMGeometricEffectDonut | CIMGeometricEffectEnclosingPolygon | CIMGeometricEffectJog | CIMGeometricEffectMove | CIMGeometricEffectOffset | CIMGeometricEffectRadial | CIMGeometricEffectRotate | CIMGeometricEffectScale | CIMGeometricEffectSuppress | CIMGeometricEffectTaperedPolygon | CIMGeometricEffectWave;

/** @since 5.0 */
export interface CIMSymbolLayer {
  /**
   * The geometric effects applied to the symbol layer. Effects dynamically alter the geometry when the symbology is applied. Multiple effects applied to a symbol layer are rendered sequentially.
   *
   * @since 5.0
   */
  effects?: CIMGeometricEffects;
  /**
   * A value indicating whether the symbol layer is visible. The symbol layer draws only when enabled.
   *
   * @since 5.0
   */
  enable: boolean;
  /**
   * A value indicating whether the color can be changed for this symbol layer. If the symbol layer is colorLocked, then any changes to the symbol's color property will not be applied to this symbol layer.
   *
   * @default false
   * @since 5.0
   */
  colorLocked?: boolean;
  /**
   * The primitive name of the symbol. Used when setting a [CIMPrimitiveOverride](https://developers.arcgis.com/javascript/latest/references/core/symbols/cim/types/#CIMPrimitiveOverride).
   *
   * @since 5.0
   */
  primitiveName?: string;
  /**
   * The animations applied to the marker.
   *
   * @since 5.0
   */
  animations?: CIMSymbolAnimation[];
}

/**
 * Represents a marker placement.
 *
 * @since 5.0
 * @see [CIMVectorMarker.markerPlacement](https://developers.arcgis.com/javascript/latest/references/core/symbols/cim/types/#CIMVectorMarker)
 * @see [CIMPictureMarker.markerPlacement](https://developers.arcgis.com/javascript/latest/references/core/symbols/cim/types/#CIMPictureMarker)
 */
export type CIMMarkerPlacement = CIMMarkerPlacementAlongLineSameSize | CIMMarkerPlacementAtExtremities | CIMMarkerPlacementAtRatioPositions | CIMMarkerPlacementInsidePolygon | CIMMarkerPlacementOnLine | CIMMarkerPlacementOnVertices | CIMMarkerPlacementPolygonCenter;

/** @since 5.0 */
export interface CIMMarker extends CIMSymbolLayer {
  /**
   * The specified location where all transformation property operations originate.
   *
   * @since 5.0
   */
  anchorPoint?: Point | null;
  /**
   * A value which specifies if the anchor point location is considered a percentage of the size or as an absolute distance.
   *
   * @default "Relative"
   * @since 5.0
   */
  anchorPointUnits?: CIMSymbolUnits;
  /**
   * The distance that the image is offset in the horizontal direction in points.
   *
   * @default 0
   * @since 5.0
   */
  offsetX?: number;
  /**
   * The distance that the image is offset in the vertical direction in points.
   *
   * @default 0
   * @since 5.0
   */
  offsetY?: number;
  /**
   * A value indicating whether the rotation is applied clockwise or counterclockwise to the marker layer.
   *
   * @default false
   * @since 5.0
   */
  rotateClockwise?: boolean;
  /**
   * The angle of the image within the fill.
   *
   * @default 0
   * @since 5.0
   */
  rotation?: number;
  /**
   * The height of the marker in points. Modifying size changes the marker's height to the specified size. The width will be updated proportionally.
   *
   * @since 5.0
   */
  size: number;
  /**
   * Determines how markers are placed along a line or within a polygon.
   *
   * @since 5.0
   */
  markerPlacement?: CIMMarkerPlacement | null;
}

/**
 * Represents color substitution, an ordered list of color substitutes.
 *
 * ```json
 * "colorSubstitutions": [
 *    {
 *       // replace all white in the image with black
 *       oldColor: [255, 255, 255, 255],
 *       newColor: [0, 0, 0, 255]
 *    }
 * ]
 * ```
 *
 * @since 5.0
 * @see [CIMPictureFill.colorSubstitutions](https://developers.arcgis.com/javascript/latest/references/core/symbols/cim/types/#CIMPictureFill)
 * @see [CIMPictureMarker.colorSubstitutions](https://developers.arcgis.com/javascript/latest/references/core/symbols/cim/types/#CIMPictureMarker)
 * @see [CIMPictureStroke.colorSubstitutions](https://developers.arcgis.com/javascript/latest/references/core/symbols/cim/types/#CIMPictureStroke)
 */
export interface CIMColorSubstitution {
  /**
   * The old color (the color that will be substituted). Value should be an array of r,b,g,a values (i.e. `[255,255,255,255]`).
   *
   * @since 5.0
   */
  oldColor: CIMColor;
  /**
   * The new color that will replace the old color. Value should be an array of r,b,g,a values (i.e. `[255,255,255,255]`).
   *
   * @since 5.0
   */
  newColor: CIMColor;
}

/** @since 5.0 */
export interface CIMGeometricEffectBase {
  /**
   * The primitive name.
   *
   * @since 5.0
   */
  primitiveName?: string;
}

/**
 * Represents the add control points geometric effect.
 * Dynamically adds geometry control points to a feature to dictate the placement of markers or other effect properties that leverage control points.
 * Control points are placed at angles or deflection based on the `angleTolerance` value.
 *
 * ```json
 * {
 *   "type": "CIMGeometricEffectAddControlPoints",
 *   "angleTolerance": 90
 * }
 * ```
 *
 * @since 4.16
 * @see [CIMGeometricEffect](https://developers.arcgis.com/javascript/latest/references/core/symbols/cim/types/#CIMGeometricEffect)
 */
export interface CIMGeometricEffectAddControlPoints extends CIMGeometricEffectBase {
  /** @since 5.0 */
  type: "CIMGeometricEffectAddControlPoints";
  /**
   * The value below which a control point will be placed. The maximum amount of deflection from one segment to another at a vertex. Angle values between 180 and 360 are interpreted the same as values between 0 and 180. Angle values of 180 and 360 are the same as 0.
   *
   * @default 120
   * @since 5.0
   */
  angleTolerance: number;
}

/**
 * Represents the arrow geometric effect which creates a dynamic line along a line feature with an arrow of a specified arrow type and width.
 *
 * ```json
 * {
 *    "type": "CIMGeometricEffectArrow",
 *    "geometricEffectArrowType": "Crossed",
 *    "width": 15
 * }
 * ```
 *
 * The following image shows what the effect defined in the code snippet above looks like on a [CIMSolidStroke](https://developers.arcgis.com/javascript/latest/references/core/symbols/cim/types/#CIMSolidStroke) symbol layer.
 *
 * ![CIMGeometricEffectArrow](https://developers.arcgis.com/javascript/latest/assets/references/core/symbols/cim/CIMGeometricEffectArrow.png)
 *
 * @since 4.16
 * @see [CIMGeometricEffect](https://developers.arcgis.com/javascript/latest/references/core/symbols/cim/types/#CIMGeometricEffect)
 */
export interface CIMGeometricEffectArrow extends CIMGeometricEffectBase {
  /** @since 5.0 */
  type: "CIMGeometricEffectArrow";
  /**
   * The type of arrow to be displayed.
   *
   * @since 5.0
   */
  arrowType: CIMGeometricEffectArrowType;
  /**
   * The distance between the lines that construct the body of the arrow.
   *
   * @since 5.0
   */
  width: number;
}

/**
 * Represents the buffer geometric effect which creates a dynamic polygon with a specified distance around features.
 *
 * ```json
 * {
 *    "type": "CIMGeometricEffectBuffer",
 *    "size": 5
 * }
 * ```
 * The following image shows what the effect defined in the code snippet above looks like on a [CIMSolidStroke](https://developers.arcgis.com/javascript/latest/references/core/symbols/cim/types/#CIMSolidStroke) symbol layer.
 *
 * ![CIMGeometricEffectBuffer](https://developers.arcgis.com/javascript/latest/assets/references/core/symbols/cim/CIMGeometricEffectBuffer.png)
 *
 * @since 4.16
 * @see [CIMGeometricEffect](https://developers.arcgis.com/javascript/latest/references/core/symbols/cim/types/#CIMGeometricEffect)
 */
export interface CIMGeometricEffectBuffer extends CIMGeometricEffectBase {
  /** @since 5.0 */
  type: "CIMGeometricEffectBuffer";
  /**
   * The distance from the feature in points. This distance is either from the edge of the marker, the edge of the stroke or the edge of the polygon outline.
   *
   * @since 5.0
   */
  size: number;
}

/**
 * Represents the control measure line geometric effect.
 *
 * @since 4.22
 * @see [CIMGeometricEffect](https://developers.arcgis.com/javascript/latest/references/core/symbols/cim/types/#CIMGeometricEffect)
 */
export interface CIMGeometricEffectControlMeasureLine extends CIMGeometricEffectBase {
  /** @since 5.0 */
  type: "CIMGeometricEffectControlMeasureLine";
  /**
   * The style of effect. Must be a value from the list of [GeometricEffectControlMeasureLineRule](https://github.com/Esri/cim-spec/blob/master/docs/v2/CIMSymbols.md#enumeration-geometriceffectcontrolmeasurelinerule).
   *
   * @since 5.0
   */
  rule: CIMGeometricEffectControlMeasureLineRule;
}

/**
 * Represents the cut geometric effect which creates a dynamic line that is shorter on one or both ends than the line feature or polygon outline.
 *
 * ```json
 * {
 *    "type": "CIMGeometricEffectCut",
 *    "beginCut": 10, // cut 10px from the beginning of the line
 *    "middleCut": 15, // cut 15px from the middle of the line
 *    "endCut": 0 // don't cut the end of the line
 * }
 * ```
 *
 * The following image shows what the effect defined in the code snippet above looks like on a [CIMSolidStroke](https://developers.arcgis.com/javascript/latest/references/core/symbols/cim/types/#CIMSolidStroke) symbol layer.
 *
 * ![CIMGeometricEffectCut](https://developers.arcgis.com/javascript/latest/assets/references/core/symbols/cim/CIMGeometricEffectCut.png)
 *
 * @since 4.16
 * @see [CIMGeometricEffect](https://developers.arcgis.com/javascript/latest/references/core/symbols/cim/types/#CIMGeometricEffect)
 */
export interface CIMGeometricEffectCut extends CIMGeometricEffectBase {
  /** @since 5.0 */
  type: "CIMGeometricEffectCut";
  /**
   * The distance from the beginning of a line that the display of the stroke starts. The beginning of the line is determined by the direction in which the line was digitized.
   *
   * @default 1
   * @since 5.0
   */
  beginCut?: number;
  /**
   * The distance from the end of a line that the display of the stroke ends. The end of the line is determined by the direction in which the line was digitized.
   *
   * @default 1
   * @since 5.0
   */
  endCut?: number;
  /**
   * The distance around the middle of a line that the display of the stroke is interrupted.
   *
   * @default 0
   * @since 5.0
   */
  middleCut?: number;
  /**
   * A value indicating whether the effect should be applied in the opposite manner. This displays the stroke symbol only at the ends of the line and leaves the rest of the line unsymbolized.
   *
   * @default false
   * @since 5.0
   */
  invert?: boolean;
}

/**
 * Represents the dashes geometric effect which creates a dynamic multipart line geometry from a line feature or the outline of a polygon based on a template.
 *
 * ```json
 * {
 *    "type": "CIMGeometricEffectDashes",
 *    "dashTemplate": [5,5,1,5], // [dash, gap, dash, gap]
 *    "lineDashEnding": "NoConstraint",
 *    "offsetAlongLine": 0
 * }
 * ```
 *
 * The following image shows what the effect defined in the code snippet above looks like on a [CIMSolidStroke](https://developers.arcgis.com/javascript/latest/references/core/symbols/cim/types/#CIMSolidStroke) symbol layer.
 *
 * ![CIMGeometricEffectDashes](https://developers.arcgis.com/javascript/latest/assets/references/core/symbols/cim/CIMGeometricEffectDashes.png)
 *
 * @since 4.16
 * @see [CIMGeometricEffect](https://developers.arcgis.com/javascript/latest/references/core/symbols/cim/types/#CIMGeometricEffect)
 */
export interface CIMGeometricEffectDashes extends CIMGeometricEffectBase {
  /** @since 5.0 */
  type: "CIMGeometricEffectDashes";
  /**
   * Where the pattern should end relative to the ending point of the geometry. Negative numbers indicate a shift to the left and positive numbers a shift to the right. This property is only applied if the `lineDashEnding` is set to `"Custom"`.
   *
   * @default 0
   * @since 5.0
   */
  customEndingOffset?: number;
  /**
   * The distance for each dash and gap. There can be multiple dash and gap values to form a complex pattern (i.e. [2,5] where 2 is the length of the dash and 5 is the length of the gap).
   *
   * @since 5.0
   */
  dashTemplate: number[] | string;
  /**
   * The setting which determines how the strokes with dash patterns are handled at the end points of the line geometry's segments.
   *
   * @default "NoConstraint"
   * @since 5.0
   */
  lineDashEnding?: CIMLineDashEnding;
  /**
   * The position where the pattern should begin relative to the starting point of the geometry. It shifts the entire pattern along the line the specified distance. Negative values indicate a shift to the left and positive numbers a shift to the right. This property is only applied if `lineDashEnding` is set to `NoConstraint` or `Custom`.
   *
   * @default 0
   * @since 5.0
   */
  offsetAlongLine?: number | null;
}

/**
 * Represents the donut geometric effect which creates a dynamic polygon ring of a specified width in relation to the outline of polygon features.
 *
 * @since 4.26
 * @see [CIMGeometricEffect](https://developers.arcgis.com/javascript/latest/references/core/symbols/cim/types/#CIMGeometricEffect)
 */
export interface CIMGeometricEffectDonut extends CIMGeometricEffectBase {
  /** @since 5.0 */
  type: "CIMGeometricEffectDonut";
  /**
   * The option for the way the symbol handles complex geometries.
   *
   * @default "Accurate"
   * @since 5.0
   */
  option?: CIMGeometricEffectOffsetOption;
  /**
   * The distance from the edge of the polygon that the fill symbol is to be displayed.
   *
   * @since 5.0
   */
  width: number;
}

/**
 * Represents the enclosing polygon geometric effect which creates a dynamic polygon from the spatial extent of a line or polygon.
 *
 * ```json
 * {
 *   "type": "CIMGeometricEffectEnclosingPolygon",
 *   "method": "ConvexHull"
 * }
 * ```
 *
 * @since 4.33
 * @see [CIMGeometricEffect](https://developers.arcgis.com/javascript/latest/references/core/symbols/cim/types/#CIMGeometricEffect)
 */
export interface CIMGeometricEffectEnclosingPolygon extends CIMGeometricEffectBase {
  /** @since 5.0 */
  type: "CIMGeometricEffectEnclosingPolygon";
  /**
   * The method which specifies the way in which the polygon geometry is generated around the feature geometry.
   *
   * @since 5.0
   */
  method: CIMGeometricEffectEnclosingPolygonMethod;
}

/**
 * Represents the jog geometric effect which creates a dynamic line with a jog of a specified angle, position, and width in the line.
 *
 * ```json
 * {
 *    "type": "CIMGeometricEffectJog",
 *    "angle": 225,
 *    "length": 20,
 *    "position": 50
 * }
 * ```
 *
 * The image below shows a [CIMSolidStroke](https://developers.arcgis.com/javascript/latest/references/core/symbols/cim/types/#CIMSolidStroke) symbol layer with the `CIMGeometricEffectJog` effect applied as defined in the snippet above.
 *
 * ![CIMGeometricEffectJog](https://developers.arcgis.com/javascript/latest/assets/references/core/symbols/cim/CIMGeometricEffectJog.png)
 *
 * @since 4.16
 * @see [CIMGeometricEffect](https://developers.arcgis.com/javascript/latest/references/core/symbols/cim/types/#CIMGeometricEffect)
 */
export interface CIMGeometricEffectJog extends CIMGeometricEffectBase {
  /** @since 5.0 */
  type: "CIMGeometricEffectJog";
  /**
   * The angle of the job in the line which is measured in degrees.
   *
   * @since 5.0
   */
  angle: number;
  /**
   * The length of the segment that forms the jog in the line.
   *
   * @since 5.0
   */
  length: number;
  /**
   * The location of the center of the jog, as a percentage measured from the start of the input geometry.
   *
   * @since 5.0
   */
  position: number;
}

/**
 * Represents the move geometric effect which creates a point, line or polygon that is offset a specified distance in X and Y.
 *
 * ```json
 * {
 *   "type": "CIMGeometricEffectMove",
 *   "offsetX": 10,
 *   "offsetY": -5
 * }
 * ```
 *
 * @since 4.16
 * @see [CIMGeometricEffect](https://developers.arcgis.com/javascript/latest/references/core/symbols/cim/types/#CIMGeometricEffect)
 */
export interface CIMGeometricEffectMove extends CIMGeometricEffectBase {
  /** @since 5.0 */
  type: "CIMGeometricEffectMove";
  /**
   * The distance in points to move the symbol along the X-axis of the feature geometry.
   *
   * @default 1
   * @since 5.0
   */
  offsetX?: number;
  /**
   * The distance in points to move the symbol along the Y-axis of the feature geometry.
   *
   * @default -1
   * @since 5.0
   */
  offsetY?: number;
}

/**
 * Represents the offset geometric effect which creates a dynamic line or polygon offset at a specified distance perpendicularly from a feature.
 *
 * ```json
 * {
 *    "type": "CIMGeometricEffectOffset",
 *    "offset": 5,
 *    "method": "Rounded",
 *    "option": "Fast"
 * }
 * ```
 *
 * @since 4.16
 * @see [CIMGeometricEffect](https://developers.arcgis.com/javascript/latest/references/core/symbols/cim/types/#CIMGeometricEffect)
 */
export interface CIMGeometricEffectOffset extends CIMGeometricEffectBase {
  /** @since 5.0 */
  type: "CIMGeometricEffectOffset";
  /**
   * The way strokes or fills are displayed at corners.
   *
   * @default "Square"
   * @since 5.0
   */
  method?: CIMGeometricEffectOffsetMethod;
  /**
   * The distance in points of the symbol perpendicular to the feature geometry.
   *
   * @since 5.0
   */
  offset: number;
  /**
   * The way the symbol handles complex geometries.
   *
   * @default "Fast"
   * @since 5.0
   */
  option?: CIMGeometricEffectOffsetOption;
}

/**
 * Represents the radial geometric effect which creates a dynamic line of a specified length and angle originating from a point feature.
 *
 * ```json
 * {
 *   "type": "CIMGeometricEffectRadial",
 *   "angle": 90,
 *   "length": 10
 * }
 *
 * @since 4.33
 * @see [CIMGeometricEffect](https://developers.arcgis.com/javascript/latest/references/core/symbols/cim/types/#CIMGeometricEffect)
 */
export interface CIMGeometricEffectRadial extends CIMGeometricEffectBase {
  /** @since 5.0 */
  type: "CIMGeometricEffectRadial";
  /**
   * The orientation of the line from the marker. The angle is calculated in a counter-clockwise manner with 0 degrees equal to due east.
   *
   * @default 0
   * @since 5.0
   */
  angle?: number;
  /**
   * The length of the radial line.
   *
   * @default 5
   * @since 5.0
   */
  length?: number;
}

/**
 * Represents the rotate geometric effect which creates a dynamic line or polygon rotated a specified angle from the feature.
 *
 * ```json
 * {
 *    // rotates the symbol 90 degrees from the symbol's geometry
 *    "type": "CIMGeometricEffectRotate",
 *    "angle": 90
 * }
 * ```
 *
 * @since 4.16
 * @see [CIMGeometricEffect](https://developers.arcgis.com/javascript/latest/references/core/symbols/cim/types/#CIMGeometricEffect)
 */
export interface CIMGeometricEffectRotate extends CIMGeometricEffectBase {
  /** @since 5.0 */
  type: "CIMGeometricEffectRotate";
  /**
   * The amount of rotation for the symbol.
   *
   * @since 5.0
   */
  angle: number;
}

/**
 * Represents the scale geometric effect which creates a dynamic line or polygon scaled by a specified factor.
 * Vertices are moved in relation to the center point of a feature envelope. Values greater than 1 move vertices
 * away from the center point. Values between 0 and 1 move vertices toward the center point. Values less than 0
 * draw an inverse dynamic line or polygon where the vertices have crossed to the other side of the center point.
 *
 * ```json
 * {
 *    "type": "CIMGeometricEffectScale",
 *    "xScaleFactor": 1.5,
 *    "yScaleFactor": 1.5
 * }
 * ```
 *
 * @since 4.16
 * @see [CIMGeometricEffect](https://developers.arcgis.com/javascript/latest/references/core/symbols/cim/types/#CIMGeometricEffect)
 */
export interface CIMGeometricEffectScale extends CIMGeometricEffectBase {
  /** @since 5.0 */
  type: "CIMGeometricEffectScale";
  /**
   * The amount of change in size of a symbol in the x-axis. The value is expressed in terms of a ratio/percentage.
   *
   * @default 1.15
   * @since 5.0
   */
  xScaleFactor?: number;
  /**
   * The amount of change in size of a symbol in the y-axis. The value is expressed in terms of a ratio/percentage.
   *
   * @default 1.15
   * @since 5.0
   */
  yScaleFactor?: number;
}

/**
 * Represents the suppress geometric effect which creates a dynamic line that hides sections of a stroke between pairs control points.
 *
 * @since 4.33
 * @see [CIMGeometricEffect](https://developers.arcgis.com/javascript/latest/references/core/symbols/cim/types/#CIMGeometricEffect)
 */
export interface CIMGeometricEffectSuppress extends CIMGeometricEffectBase {
  /** @since 5.0 */
  type: "CIMGeometricEffectSuppress";
  /**
   * A value indicating whether the portion of the stroke symbol between control points should be suppressed. Sections that are suppressed draw with no symbol.
   *
   * @default false
   * @since 5.0
   */
  suppress: boolean;
  /**
   * A value indicating whether to invert the suppression process. If this value is `true`, portions of the stroke symbol between the control points are kept and all other portions are suppressed.
   *
   * @default false
   * @since 5.0
   */
  invert?: boolean;
}

/**
 * Represents the tapered polygon geometric effect which creates a dynamic polygon along a line feature, whose width varies by two specified amounts along its length, as defined by a percentage of the line feature's length.
 *
 * @since 4.33
 * @see [CIMGeometricEffect](https://developers.arcgis.com/javascript/latest/references/core/symbols/cim/types/#CIMGeometricEffect)
 */
export interface CIMGeometricEffectTaperedPolygon extends CIMGeometricEffectBase {
  /** @since 5.0 */
  type: "CIMGeometricEffectTaperedPolygon";
  /**
   * The width at the start of the line to be used to generate the polygon.
   *
   * @default 0
   * @since 5.0
   */
  fromWidth: number;
  /**
   * The distance along the line to be used to generate the polygon.
   *
   * @default 0
   * @since 5.0
   */
  length: number;
  /**
   * The width at the end of the line to be used to generate the polygon.
   *
   * @default 1
   * @since 5.0
   */
  toWidth: number;
}

/**
 * Represents the wave geometric effect which creates a dynamic line or polygon along a feature with a repeating wave pattern.
 *
 * ```json
 * {
 *    "type": "CIMGeometricEffectWave",
 *    "amplitude": 5,
 *    "period": 5,
 *    "waveform": "Square"
 * }
 * ```
 *
 * The image below shows a [CIMSolidStroke](https://developers.arcgis.com/javascript/latest/references/core/symbols/cim/types/#CIMSolidStroke) symbol layer with the `CIMGeometricEffectWave` effect applied as defined in the snippet above.
 *
 * ![CIMGeometricEffectWave](https://developers.arcgis.com/javascript/latest/assets/references/core/symbols/cim/CIMGeometricEffectWave.png)
 *
 * @since 4.16
 * @see [CIMGeometricEffect](https://developers.arcgis.com/javascript/latest/references/core/symbols/cim/types/#CIMGeometricEffect)
 */
export interface CIMGeometricEffectWave extends CIMGeometricEffectBase {
  /** @since 5.0 */
  type: "CIMGeometricEffectWave";
  /**
   * The distance perpendicular to a feature to display the curves for the symbol.
   *
   * @default 2
   * @since 5.0
   */
  amplitude: number;
  /**
   * The distance along the line or polygon to display the curves for the symbol.
   *
   * @default 3
   * @since 5.0
   */
  period: number;
  /**
   * The starting value for generating a random number. This is only used when the `waveform` is set to `"Random"`.
   *
   * @default 1
   * @since 5.0
   */
  seed?: number;
  /**
   * The shape of the curves to be displayed along the symbol.
   *
   * @default "Sinus"
   * @since 5.0
   */
  waveform?: CIMGeometricEffectWaveform;
}

/** @since 5.0 */
export interface CIMFill extends CIMSymbolLayer {}

/**
 * Represents a gradient fill which fills polygonal geometry with a specified color scheme.
 *
 * ```json
 * {
 *   type: "CIMGradientFill",
 *   enable: true,
 *   gradientMethod: "Circular",
 *   gradientSize: 70,
 *   gradientSizeUnits: "Relative",
 *   gradientType: "Continuous",
 *   colorRamp: {
 *     type: "CIMMultipartColorRamp",
 *     colorRamps: [
 *       {
 *         type: "CIMLinearContinuousColorRamp",
 *         fromColor: [0, 76, 115, 255],
 *         toColor: [0, 132, 168, 255]
 *       },
 *       {
 *         type: "CIMLinearContinuousColorRamp",
 *         fromColor: [0, 132, 168, 255],
 *         toColor: [255, 255, 255, 255]
 *       }
 *     ],
 *     weights: [0.3, 0.7]
 *   }
 * }
 * ```
 *
 * @since 4.32
 */
export interface CIMGradientFill extends CIMFill {
  /** @since 5.0 */
  type: "CIMGradientFill";
  /**
   * The angle of the gradient when the GradientMethod is set to "Linear" or "Rectangular".
   *
   * @default 90
   * @since 5.0
   */
  angle?: number;
  /**
   * The color ramp that is applied to the gradient fill.
   *
   * @since 5.0
   */
  colorRamp: CIMColorRampUnion;
  /**
   * The method used to specify how the gradient is applied within the fill.
   *
   * @default "Linear"
   * @since 5.0
   */
  gradientMethod?: CIMGradientFillMethod;
  /**
   * The size which determines the how much of the feature is covered by the color scheme. This is either a percentage of the total area which the color scheme spans (if units are "Relative") or the number of points from the starting point at which the gradient displays (if units are "Absolute").
   *
   * @default 75
   * @since 5.0
   */
  gradientSize?: number;
  /**
   * The units which determine if the `gradientSize` is applied with an absolute distance or a relative percentage.
   *
   * @default "Relative"
   * @since 5.0
   */
  gradientSizeUnits?: CIMSymbolUnits;
  /**
   * The type which specifies if the gradient is applied with discrete intervals or if it is continuous.
   *
   * @default "Discrete"
   * @since 5.0
   */
  gradientType?: CIMGradientStrokeType;
  /**
   * The interval which specifies the number of discrete intervals in the gradient. This property is only applied when the `gradientType` is set to "Discrete".
   *
   * @default 5
   * @since 5.0
   */
  interval?: number;
}

/**
 * Represents a stroke which draws linear geometry with specified visual properties.
 *
 * @since 5.0
 */
export interface CIMStroke extends CIMSymbolLayer {
  /**
   * Determines how the stroke should draw at the ends of the geometries.
   *
   * @default "Round"
   * @since 5.0
   */
  capStyle?: CIMLineCapStyle;
  /**
   * Determines how the symbol is drawn at the stroke segment connections.
   *
   * @default "Round"
   * @since 5.0
   */
  joinStyle?: CIMLineJoinStyle;
  /**
   * The maximum 'sharpness' that is allowed for miter joins. The sharp angle will be clipped and rendered with a bevel join if the spike created by the miter join exceeds the `miterLimit` multiplied by the width of the stroke. This property is only applied to the symbol layer when the `joinStyle` is set to `Miter`.
   *
   * @default 4
   * @since 5.0
   */
  miterLimit?: number;
  /**
   * The width of the stroke.
   *
   * @since 5.0
   */
  width: number;
}

/**
 * Represents a gradient stroke which draws linear geometry with a specified color scheme.
 *
 * ```json
 * {
 *   type: "CIMGradientStroke",
 *   enable: true,
 *   gradientMethod: "AcrossLine",
 *   gradientSize: 100,
 *   gradientSizeUnits: "Relative",
 *   gradientType: "Continuous",
 *   capStyle: "Round",
 *   joinStyle: "Round",
 *   miterLimit: 4,
 *   width: 12,
 *   colorRamp: {
 *     type: "CIMMultipartColorRamp",
 *     colorRamps: [
 *       {
 *         type: "CIMLinearContinuousColorRamp",
 *         fromColor: [255, 255, 255, 255], // white
 *         toColor: [190, 232, 255, 255] // light blue
 *       }
 *     ],
 *     weights: [1]
 *   }
 * }
 *  ```
 *
 * @since 4.32
 */
export interface CIMGradientStroke extends CIMStroke {
  /** @since 5.0 */
  type: "CIMGradientStroke";
  /**
   * The color ramp that is applied to the gradient stroke.
   *
   * @since 5.0
   */
  colorRamp: CIMColorRampUnion;
  /**
   * The method used to specify how the gradient is applied along the stroke.
   *
   * @since 5.0
   */
  gradientMethod?: CIMGradientStrokeMethod;
  /**
   * The size which determines the how much of the feature is covered by the color scheme. This is either a percentage of the total area which the color scheme spans (if units are "Relative") or the number of points from the starting point at which the gradient displays (if units are "Absolute").
   *
   * @default 75
   * @since 5.0
   */
  gradientSize?: number;
  /**
   * The units which determine if the `gradientSize` is applied with an absolute distance or a relative percentage.
   *
   * @default "Relative"
   * @since 5.0
   */
  gradientSizeUnits?: CIMSymbolUnits;
  /**
   * The type which specifies if the gradient is applied with discrete intervals or if it is continuous.
   *
   * @default "Discrete"
   * @since 5.0
   */
  gradientType?: CIMGradientStrokeType;
  /**
   * The interval which specifies the number of discrete intervals in the gradient. This property is only applied when the `gradientType` is set to "Discrete".
   *
   * @default 5
   * @since 5.0
   */
  interval?: number;
}

/**
 * Represents a hatch fill which fills polygonal geometry with a uniform series of parallel line symbols.
 *
 * ```json
 * {
 *   "type": "CIMHatchFill",
 *   "enable": true,
 *   "lineSymbol": {
 *      "type": "CIMLineSymbol",
 *      "symbolLayers": [{
 *         "type": "CIMSolidStroke",
 *         "enable": true,
 *         "capStyle": "Butt",
 *         "joinStyle": "Miter",
 *         "miterLimit": 10,
 *         "width": 1,
 *         "color": [255, 61, 61, 255]
 *      }]
 *   },
 *   "rotation": 45,
 *   "separation": 5
 * }
 * ```
 *
 * The following image shows a [CIMPolygonSymbol](https://developers.arcgis.com/javascript/latest/references/core/symbols/cim/types/#CIMPolygonSymbol) with a `CIMHatchFill` symbol layer (as defined in the code snippet above).
 * ![CIMHatchFill](https://developers.arcgis.com/javascript/latest/assets/references/core/symbols/cim/CIMHatchFill.png)
 *
 * @since 5.0
 * @see [CIMSymbolLayer](https://developers.arcgis.com/javascript/latest/references/core/symbols/cim/types/#CIMSymbolLayer)
 */
export interface CIMHatchFill extends CIMFill {
  /** @since 5.0 */
  type: "CIMHatchFill";
  /**
   * The line symbol that is used to draw the hatch lines in the fill.
   *
   * @since 5.0
   */
  lineSymbol: CIMLineSymbol;
  /**
   * How much to move the stroke in points to a new X-position.
   *
   * @default 0
   * @since 5.0
   */
  offsetX?: number;
  /**
   * How much to move the stroke in points to a new Y-position.
   *
   * @default 0
   * @since 5.0
   */
  offsetY?: number;
  /**
   * The angle of rotation for all the strokes, in degrees.
   *
   * @default 0
   * @since 5.0
   */
  rotation?: number;
  /**
   * The distance between the line symbols in the hatch pattern.
   *
   * @since 5.0
   */
  separation?: number;
}

/** @since 5.0 */
export interface CIMExpressionInfo {
  /** @since 5.0 */
  type: "CIMExpressionInfo";
  /**
   * The human readable text that describes the expression.
   *
   * @since 5.0
   */
  title?: string;
  /**
   * An [Arcade](https://developers.arcgis.com/javascript/latest/arcade/) expression following the specification defined by the [Arcade Visualization Profile](https://developers.arcgis.com/javascript/latest/arcade/#visualization). Expressions in primitive overrides may reference field values using the `$feature` profile variable and must return a number or a string. The value returned from this expression represents the value override for the specified `propertyName`. For example, when overriding a symbol layer's color, you must return a string representing a color (e.g. `"rgb(255,255,255)"`, `"white"`, or `"#ffffff"`). When overriding a size, you must return a number representing the new size of the symbol layer.
   *
   * @since 5.0
   */
  expression: string;
  /**
   * The name of the expression.
   *
   * @since 5.0
   */
  name?: string;
  /**
   * The return type of the expression. `"Default"` means the return type of the expression is determined by the consumer using the expression.
   *
   * @since 5.0
   */
  returnType?: CIMExpressionReturnType;
}

/**
 * Represents a symbol reference from the [CIMSymbol.data](https://developers.arcgis.com/javascript/latest/references/core/symbols/CIMSymbol/#data) property.
 *
 * @since 5.0
 * @see [CIMSymbol.data](https://developers.arcgis.com/javascript/latest/references/core/symbols/CIMSymbol/#data)
 */
export interface CIMSymbolReference {
  /** @since 5.0 */
  type: "CIMSymbolReference";
  /**
   * The primitive overrides. These allow you to use [Arcade expressions](https://developers.arcgis.com/javascript/latest/arcade/#visualization) to dynamically change many symbol layer properties
   *    from data values.
   *
   * @since 5.0
   */
  primitiveOverrides?: CIMPrimitiveOverride[] | null;
  /**
   * The symbol. Supported values are CIMPointSymbol, CIMLineSymbol, and CIMPolygonSymbol.
   *
   * @since 5.0
   */
  symbol?: CIMSymbolUnion | null;
  /**
   * The minimum scale the symbol reference should be displayed. To show your symbol at all scales, set `minScale` and `maxScale` to `0`.
   *
   * @since 5.0
   */
  minScale?: number;
  /**
   * The maximum scale the symbol reference should be displayed. To show your symbol at all scales, set `minScale` and `maxScale` to `0`.
   *
   * @since 5.0
   */
  maxScale?: number;
}

/**
 * The base interface for all CIM symbols.
 *
 * @since 5.0
 */
export interface CIMSymbol {}

/**
 * Represents a symbol layer, the component that makes up a symbol. A symbol layer is represented by a marker, stroke, or fill symbol layer.
 * Symbol layers are the building blocks of CIM symbols, they combine to make rich graphical depictions. You can configure the shape, color,
 * texture, size, position, etc of each symbol layer, and combine multiple symbol layers to create your desired symbol. The symbol layers are
 * typically displayed in the order they are defined, so the first symbol layer will be displayed on top, and the last symbol layer will be
 * displayed on bottom.
 *
 * > [!WARNING]
 * >
 * > **Known Limitations**
 * >
 * > CIMSymbols within a FeatureLayer will render the symbol layers in the following order from top to bottom for performance reasons, regardless of the order they are defined within the symbol.
 * > 1. CIMTextSymbol embedded within a CIMVectorMarker symbol layer
 * > 2. Marker symbols - CIMVectorMarker and CIMPictureMarker
 * > 3. Stroke symbols - CIMSolidStroke, CIMPictureStroke, and CIMGradientStroke
 * > 4. Fill symbols - CIMSolidFill, CIMHatchFill, CIMPictureFill, and CIMGradientFill
 *
 * @since 5.0
 * @see [CIMPointSymbol.symbolLayers](https://developers.arcgis.com/javascript/latest/references/core/symbols/cim/types/#CIMPointSymbol)
 * @see [CIMLineSymbol.symbolLayers](https://developers.arcgis.com/javascript/latest/references/core/symbols/cim/types/#CIMLineSymbol)
 * @see [CIMPolygonSymbol.symbolLayers](https://developers.arcgis.com/javascript/latest/references/core/symbols/cim/types/#CIMPolygonSymbol)
 */
export type CIMSymbolLayerUnion = CIMGradientFill | CIMPictureMarker | CIMVectorMarker | CIMGradientStroke | CIMHatchFill | CIMPictureFill | CIMPictureStroke | CIMSolidFill | CIMSolidStroke;

/**
 * Represents a multi-layer symbol which is a symbol composed of multiple symbol layers.
 *
 * @since 5.0
 */
export interface CIMMultiLayerSymbol extends CIMSymbol {
  /**
   * The geometric effects applied to the symbol.
   *
   * @since 5.0
   */
  effects?: CIMGeometricEffects;
  /**
   * The symbol layers. Symbol layers are the components that make up a symbol. A symbol layer is represented by a marker, stroke, or fill symbol layer. Symbol layers are the building blocks of CIM symbols, they combine to make rich graphical depictions. You can configure the shape, color, texture, size, position, etc of each symbol layer, and combine multiple symbol layers to create your desired symbol. The symbol layers are typically displayed in the order they are defined, so the first symbol layer will be displayed on top, and the last symbol layer will be displayed on bottom. There are some limitations to this when working with FeatureLayers - see [CIMSymbolLayer](https://developers.arcgis.com/javascript/latest/references/core/symbols/cim/types/#CIMSymbolLayer) for more information.
   *
   * @since 5.0
   */
  symbolLayers?: CIMSymbolLayerUnion[];
  /**
   * A value indicating whether the symbol size properties are rendered using real world units or page units. When set to `true`, the symbol will draw using real world units (e.g. meters).
   *
   * @since 5.0
   */
  useRealWorldSymbolSizes?: boolean;
}

/**
 * Represents a line symbol used to draw polyline features and graphics.
 *
 * The code snippet below shows an example of a CIMLineSymbol with one
 * [CIMSolidStroke](https://developers.arcgis.com/javascript/latest/references/core/symbols/cim/types/#CIMSolidStroke) symbol layer with a
 * [dash effect](https://developers.arcgis.com/javascript/latest/references/core/symbols/cim/types/#CIMGeometricEffectDashes) on top of another CIMSolidStroke layer as shown below.
 *
 * ![CIMLineSymbol](https://developers.arcgis.com/javascript/latest/assets/references/core/symbols/symbol-cim-line.png)
 *
 * ```js
 * const lineSymbol = new CIMSymbol({
 *   data: {
 *     type: "CIMSymbolReference",
 *     symbol: {
 *        type: "CIMLineSymbol",
 *        symbolLayers: [{
 *          type: "CIMSolidStroke",
 *          effects: [{
 *            type: "CIMGeometricEffectDashes",
 *            dashTemplate: [5, 5],
 *            lineDashEnding: "FullGap",
 *            controlPointEnding: "NoConstraint"
 *          }],
 *          enable: "true",
 *          capStyle: "Butt",
 *          joinStyle: "Round",
 *          width: 2.6,
 *          color: [255, 255, 255, 255]
 *        },
 *        {
 *          type: "CIMSolidStroke",
 *          enable: true,
 *          capStyle: "Butt",
 *          joinStyle: "Round",
 *          width: 3.4,
 *          color: [0, 0, 0, 255]
 *        }]
 *     }
 *   }
 * });
 * ```
 *
 * > [!WARNING]
 * >
 * > - CIMLineSymbol is not currently supported in 3D SceneViews.
 *
 * @since 4.16
 * @see [CIMSymbolReference.symbol](https://developers.arcgis.com/javascript/latest/references/core/symbols/cim/types/#CIMSymbolReference)
 * @see [CIMMarkerGraphic.symbol](https://developers.arcgis.com/javascript/latest/references/core/symbols/cim/types/#CIMMarkerGraphic)
 * @see [CIMHatchFill.lineSymbol](https://developers.arcgis.com/javascript/latest/references/core/symbols/cim/types/#CIMHatchFill)
 */
export interface CIMLineSymbol extends CIMMultiLayerSymbol {
  /** @since 5.0 */
  type: "CIMLineSymbol";
}

/**
 * Represents a marker graphic which is used to define vector graphics in a vector marker.
 * The marker graphics are typically rendered from bottom to top, so the first marker graphic will be displayed at the bottom, and the last marker graphic will be displayed on top.
 *
 * > [!WARNING]
 * >
 * > **Known limitation**
 * >
 * > For CIMSymbols in a FeatureLayer, a marker graphic that contains a CIMTextSymbol will always be rendered on top, regardless of its order in the array of graphics.
 *
 * @since 5.0
 * @see [CIMVectorMarker.markerGraphics](https://developers.arcgis.com/javascript/latest/references/core/symbols/cim/types/#CIMVectorMarker)
 */
export interface CIMMarkerGraphic {
  /** @since 5.0 */
  type: "CIMMarkerGraphic";
  /**
   * The geometry of the marker.
   *
   * @since 5.0
   */
  geometry: any;
  /**
   * The symbol used to draw the marker graphic. This can be a point, line, polygon or text symbol.
   *
   * @since 5.0
   */
  symbol?: CIMSymbolUnion;
  /**
   * The text that is defined within the marker if drawn with a text symbol.
   *
   * @since 5.0
   */
  textString?: string;
  /**
   * The primitive name.
   *
   * @since 5.0
   */
  primitiveName?: string;
}

/**
 * The base interface for all CIM marker placements.
 *
 * @since 5.0
 */
export interface CIMMarkerPlacementBase {
  /**
   * The primitive name.
   *
   * @since 5.0
   */
  primitiveName?: string;
  /**
   * A value indicating whether to consider individual geometry parts or the whole geometry.
   *
   * @default true
   * @since 5.0
   */
  placePerPart?: boolean;
}

/**
 * The base interface for all CIM marker placements along a stroke.
 *
 * @since 5.0
 */
export interface CIMMarkerStrokePlacement extends CIMMarkerPlacementBase {
  /**
   * A value indicating whether to angle the marker to the line.
   *
   * @default true
   * @since 5.0
   */
  angleToLine?: boolean;
  /**
   * A value indicating whether to keep the marker upright. This is only considered if `angleToLine` is true.
   *
   * @default false
   * @since 5.0
   */
  keepUpright: boolean;
  /**
   * The offset in points.
   *
   * @default 0
   * @since 5.0
   */
  offset?: number;
}

/**
 * The base interface for all CIM marker placements along a line.
 *
 * @since 5.0
 */
export interface CIMMarkerPlacementAlongLine extends CIMMarkerStrokePlacement {
  /**
   * Where the pattern should end relative to the ending point of the geometry. The entire pattern is shifted along the line for the specified distance. Negative numbers shift to the left and positive numbers shift to the right. This is only applied if the `endings` property is set to `Custom`.
   *
   * @default 0
   * @since 5.0
   */
  customEndingOffset?: number;
  /**
   * How markers are placed at the end points of a line.
   *
   * @default "WithHalfGap"
   * @since 5.0
   */
  endings?: CIMPlacementEndings;
  /**
   * Where the pattern should begin relative to the starting point of the geometry. The entire pattern is shifted along the line for the specified distance. Negative numbers shift to the left and positive numbers shift to the right. This is only applied if the `endings` property is set to `No Constraint` or `Custom`.
   *
   * @default 0
   * @since 5.0
   */
  offsetAlongLine?: number;
  /**
   * The numeric pattern that defines the sequence of placed markers and the length of space between them.
   *
   * @since 5.0
   */
  placementTemplate: number[];
}

/**
 * Represents marker placement along the line which places markers that are the same size evenly along a line or polygon outline.
 *
 * ```json
 * "markerPlacement": {
 *    "type": "CIMMarkerPlacementAlongLineSameSize",
 *    "angleToLine": true,
 *    "offset": 0,
 *    "controlPointsPlacement": "NoConstraint",
 *    "customEndingOffset": 0,
 *    "endings": "NoConstraint",
 *    "offsetAlongLine": 0,
 *    "placementTemplate": [10, 10]
 * }
 * ```
 *
 * The following image shows what the marker placement defined in the code snippet above looks like on a circular [CIMVectorMarker](https://developers.arcgis.com/javascript/latest/references/core/symbols/cim/types/#CIMVectorMarker) symbol layer.
 *
 * ![CIMMarkerPlacementAlongLineSameSize](https://developers.arcgis.com/javascript/latest/assets/references/core/symbols/cim/CIMMarkerPlacementAlongLineSameSize.png)
 *
 * @since 5.0
 * @see [CIMMarkerPlacement](https://developers.arcgis.com/javascript/latest/references/core/symbols/cim/types/#CIMMarkerPlacement)
 * @see [Sample - Arrows along a line](https://developers.arcgis.com/javascript/latest/sample-code/cim-line-arrows/)
 */
export interface CIMMarkerPlacementAlongLineSameSize extends CIMMarkerPlacementAlongLine {
  /** @since 5.0 */
  type: "CIMMarkerPlacementAlongLineSameSize";
}

/**
 * Represents marker placement at extremities which places markers at only one or both endpoints of a line.
 *
 * ```json
 * "markerPlacement": {
 *    "type": "CIMMarkerPlacementAtExtremities",
 *    "angleToLine": true,
 *    "offset": 0,
 *    "extremityPlacement": "Both",
 *    "offsetAlongLine": 0
 * }
 * ```
 *
 * The following image shows what the marker placement defined in the code snippet above looks like on a circular [CIMVectorMarker](https://developers.arcgis.com/javascript/latest/references/core/symbols/cim/types/#CIMVectorMarker) symbol layer.
 *
 * ![CIMMarkerPlacementAtExtremities](https://developers.arcgis.com/javascript/latest/assets/references/core/symbols/cim/CIMMarkerPlacementAtExtremities.png)
 *
 * @since 5.0
 * @see [CIMMarkerPlacement](https://developers.arcgis.com/javascript/latest/references/core/symbols/cim/types/#CIMMarkerPlacement)
 */
export interface CIMMarkerPlacementAtExtremities extends CIMMarkerStrokePlacement {
  /** @since 5.0 */
  type: "CIMMarkerPlacementAtExtremities";
  /**
   * Which ends of the line a marker will be placed.
   *
   * @default "Both"
   * @since 5.0
   */
  extremityPlacement?: CIMExtremityPlacement;
  /**
   * The distance (in points) from the ends of a line that the marker will be placed.
   *
   * @default 0
   * @since 5.0
   */
  offsetAlongLine?: number;
}

/**
 * Represents marker placement at ratio positions which places a set number of markers along the line or the outline of a polygon.
 *
 * ```json
 * "markerPlacement": {
 *    "type": "CIMMarkerPlacementAtRatioPositions",
 *    "angleToLine": true,
 *    "offset": 0,
 *    "beginPosition": 0,
 *    "endPosition": 0,
 *    "flipFirst": false,
 *    "positionArray": ["0", "0.5"]
 * }
 * ```
 *
 * The following image shows what the marker placement defined in the code snippet above looks like on a circular [CIMVectorMarker](https://developers.arcgis.com/javascript/latest/references/core/symbols/cim/types/#CIMVectorMarker) symbol layer.
 *
 * ![CIMMarkerPlacementAtRatioPositions](https://developers.arcgis.com/javascript/latest/assets/references/core/symbols/cim/CIMMarkerPlacementAtRatioPositions.png)
 *
 * @since 5.0
 * @see [CIMMarkerPlacement](https://developers.arcgis.com/javascript/latest/references/core/symbols/cim/types/#CIMMarkerPlacement)
 */
export interface CIMMarkerPlacementAtRatioPositions extends CIMMarkerStrokePlacement {
  /** @since 5.0 */
  type: "CIMMarkerPlacementAtRatioPositions";
  /**
   * The distance from the beginning of a line that the marker will be placed.
   *
   * @default 0
   * @since 5.0
   */
  beginPosition?: number;
  /**
   * The distance from the end of a line that the marker will be placed. The ending of a line is determined by the direction in which the line was digitized.
   *
   * @default 0
   * @since 5.0
   */
  endPosition?: number;
  /**
   * A value indicating whether only the first marker will be rotated 180 degrees.
   *
   * @default true
   * @since 5.0
   */
  flipFirst?: boolean;
  /**
   * The array of positions.
   *
   * @since 5.0
   */
  positionArray: number[];
}

/**
 * The base interface for all CIM marker placements inside a polygon.
 *
 * @since 5.0
 */
export interface CIMMarkerFillPlacement extends CIMMarkerPlacementBase {}

/**
 * Represents marker placement inside a polygon which defines how a polygon is filled with a pattern of markers.
 *
 * ```json
 * "markerPlacement": {
 *    "type": "CIMMarkerPlacementInsidePolygon",
 *    "gridAngle": 0,
 *    "offsetX": 0,
 *    "offsetY": 0,
 *    "stepX": 20,
 *    "stepY": 20,
 *    "shiftOddRows": true
 * }
 * ```
 *
 * The following image shows what the marker placement defined in the code snippet above looks like on a circular [CIMVectorMarker](https://developers.arcgis.com/javascript/latest/references/core/symbols/cim/types/#CIMVectorMarker) symbol layer.
 *
 * ![CIMMarkerPlacementInsidePolygon](https://developers.arcgis.com/javascript/latest/assets/references/core/symbols/cim/CIMMarkerPlacementInsidePolygon.png)
 *
 * @since 5.0
 * @see [CIMMarkerPlacement](https://developers.arcgis.com/javascript/latest/references/core/symbols/cim/types/#CIMMarkerPlacement)
 * @see [Sample - Adjust marker placement in polygon symbols](https://developers.arcgis.com/javascript/latest/sample-code/cim-marker-placement/)
 */
export interface CIMMarkerPlacementInsidePolygon extends CIMMarkerFillPlacement {
  /** @since 5.0 */
  type: "CIMMarkerPlacementInsidePolygon";
  /**
   * The orientation angle that the markers are placed on within the polygon.
   *
   * @default 0
   * @since 5.0
   */
  gridAngle?: number;
  /**
   * The grid type which defines how markers are placed. `Random` is supported as of version 4.24.
   *
   * @default "Fixed"
   * @since 5.0
   */
  gridType?: CIMPlacementGridType;
  /**
   * The marker row offset horizontally in points.
   *
   * @default 0
   * @since 5.0
   */
  offsetX?: number;
  /**
   * The marker row offset vertically in points.
   *
   * @default 0
   * @since 5.0
   */
  offsetY?: number;
  /**
   * A percentage that determines the randomness of markers within the polygon. Accepted values are between 0 and 100, with 0 being the least random and 100 being the most random. Only applied when `gridType` is `Random`.
   *
   * @default 100
   * @since 5.0
   */
  randomness?: number;
  /**
   * The starting value for generating a random pattern. Only applied when `gridType` is `Random`.
   *
   * @default 0
   * @since 5.0
   */
  seed?: number;
  /**
   * A value indicating whether every other row of markers should be shifted to create an offset grid.
   *
   * @default false
   * @since 5.0
   */
  shiftOddRows?: boolean;
  /**
   * The distance between each marker on the X-axis of the grid.
   *
   * @since 5.0
   */
  stepX: number;
  /**
   * The distance between each marker on the Y-axis of the grid.
   *
   * @since 5.0
   */
  stepY: number;
}

/**
 * Represents a marker placement on the line.
 *
 * ```json
 * "markerPlacement": {
 *    "type": "CIMMarkerPlacementOnLine",
 *    "angleToLine": true,
 *    "offset": 0,
 *    "relativeTo": "LineMiddle",
 *    "startPointOffset": 0
 * }
 * ```
 *
 * The following image shows what the marker placement defined in the code snippet above looks like on a circular [CIMVectorMarker](https://developers.arcgis.com/javascript/latest/references/core/symbols/cim/types/#CIMVectorMarker) symbol layer.
 *
 * ![CIMMarkerPlacementOnLine](https://developers.arcgis.com/javascript/latest/assets/references/core/symbols/cim/CIMMarkerPlacementOnLine.png)
 *
 * @since 5.0
 * @see [CIMMarkerPlacement](https://developers.arcgis.com/javascript/latest/references/core/symbols/cim/types/#CIMMarkerPlacement)
 */
export interface CIMMarkerPlacementOnLine extends CIMMarkerStrokePlacement {
  /** @since 5.0 */
  type: "CIMMarkerPlacementOnLine";
  /**
   * The location on a line where a marker will be placed. The direction of the line is determined by the direction in which the line was digitized.
   *
   * @default "LineMiddle"
   * @since 5.0
   */
  relativeTo?: CIMPlacementOnLineRelativeTo;
  /**
   * The distance in points from a specified location on a line that a marker will be placed.
   *
   * @default 0
   * @since 5.0
   */
  startPointOffset?: number;
}

/**
 * Represents a marker placement on vertices which places a single marker on a line or polygon outline at a set distance from the middle or one of the endpoints.
 *
 * ```json
 * "markerPlacement": {
 *    "type": "CIMMarkerPlacementOnVertices",
 *    "angleToLine": true,
 *    "offset": 0,
 *    "placeOnEndPoints": true,
 *    "placeOnRegularVertices": true
 * }
 * ```
 *
 * The following image shows what the marker placement defined in the code snippet above looks like on a circular [CIMVectorMarker](https://developers.arcgis.com/javascript/latest/references/core/symbols/cim/types/#CIMVectorMarker) symbol layer.
 *
 * ![CIMMarkerPlacementOnVertices](https://developers.arcgis.com/javascript/latest/assets/references/core/symbols/cim/CIMMarkerPlacementOnVertices.png)
 *
 * @since 5.0
 * @see [CIMMarkerPlacement](https://developers.arcgis.com/javascript/latest/references/core/symbols/cim/types/#CIMMarkerPlacement)
 */
export interface CIMMarkerPlacementOnVertices extends CIMMarkerStrokePlacement {
  /** @since 5.0 */
  type: "CIMMarkerPlacementOnVertices";
  /**
   * A value indicating whether a marker will be placed on the control points of the line.
   *
   * @default true
   * @since 5.0
   */
  placeOnControlPoints?: boolean;
  /**
   * A value indicating whether a marker will be placed on the endpoints of the line.
   *
   * @default true
   * @since 5.0
   */
  placeOnEndPoints?: boolean;
  /**
   * A value indicating whether a marker will be placed on the vertices of the line.
   *
   * @default true
   * @since 5.0
   */
  placeOnRegularVertices?: boolean;
}

/**
 * Represents marker placement polygon center which defines how a single marker will be placed within the polygon.
 *
 * ```json
 * "markerPlacement": {
 *    "type": "CIMMarkerPlacementPolygonCenter",
 *    "method": "OnPolygon",
 *    "offsetX": 0,
 *    "offsetY": 0,
 *    "clipAtBoundary": false
 * }
 * ```
 *
 * The following image shows what the marker placement defined in the code snippet above looks like on a circular [CIMVectorMarker](https://developers.arcgis.com/javascript/latest/references/core/symbols/cim/types/#CIMVectorMarker) symbol layer.
 *
 * ![CIMMarkerPlacementPolygonCenter](https://developers.arcgis.com/javascript/latest/assets/references/core/symbols/cim/CIMMarkerPlacementPolygonCenter.png)
 *
 * @since 5.0
 * @see [CIMMarkerPlacement](https://developers.arcgis.com/javascript/latest/references/core/symbols/cim/types/#CIMMarkerPlacement)
 */
export interface CIMMarkerPlacementPolygonCenter extends CIMMarkerFillPlacement {
  /** @since 5.0 */
  type: "CIMMarkerPlacementPolygonCenter";
  /**
   * The method used to determine the polygon center.
   *
   * @default "OnPolygon"
   * @since 5.0
   */
  method?: CIMPlacementPolygonCenterMethod;
  /**
   * The value which offsets the marker horizontally from the center in points.
   *
   * @default 0
   * @since 5.0
   */
  offsetX?: number;
  /**
   * The value which offsets the marker vertically from the center in points.
   *
   * @default 0
   * @since 5.0
   */
  offsetY?: number;
  /**
   * A value indicating whether the marker should be clipped if it extends pasts the boundary of the polygon.
   *
   * @default false
   * @since 5.0
   */
  clipAtBoundary?: boolean;
}

